// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.junit.jupiter.api.Test;

class CostOrderingTest {

	@Test
	void exactAndBoundedRankRawExecutionResourcesOnly() {
		ExecutionCost raw = work(100.0d);
		EstimateRisk uncertain = risk(3.0d, 0.10d);

		for (OptimizationGoal.CostPolicy policy : new OptimizationGoal.CostPolicy[] {
				OptimizationGoal.CostPolicy.EXACT,
				OptimizationGoal.CostPolicy.BOUNDED }) {
			CostOrdering.RankedCost ranked = CostOrdering.forPolicy(policy)
					.rank(raw, uncertain, PhysicalOperatorId.of("scan"));

			assertEquals(raw, ranked.resources(), policy + " must not price estimate risk into execution cost");
		}
	}

	@Test
	void robustTransformsRawResourcesExactlyOnce() {
		CostOrdering.RankedCost ranked = CostOrdering.forPolicy(OptimizationGoal.CostPolicy.ROBUST)
				.rank(work(100.0d), risk(3.0d, 1.0d), PhysicalOperatorId.of("uncertain-scan"));

		assertEquals(300.0d, ranked.resources().totalWork(), 0.0d,
				"A threefold risk adjustment must transform raw work from 100 to 300 exactly once");
		assertNotEquals(900.0d, ranked.resources().totalWork(), 0.0d,
				"Ranking must not robust-adjust an already transformed resource cost");
	}

	@Test
	void feedbackAwareTransformsOnlyAtConfidenceThreshold() {
		CostOrdering ordering = CostOrdering.forPolicy(OptimizationGoal.CostPolicy.FEEDBACK_AWARE);
		ExecutionCost raw = work(100.0d);

		CostOrdering.RankedCost belowThreshold = ordering.rank(raw, risk(3.0d, 0.54d),
				PhysicalOperatorId.of("weak-feedback"));
		CostOrdering.RankedCost atThreshold = ordering.rank(raw, risk(3.0d, 0.55d),
				PhysicalOperatorId.of("trusted-feedback"));

		assertEquals(100.0d, belowThreshold.resources().totalWork(), 0.0d);
		assertEquals(300.0d, atThreshold.resources().totalWork(), 0.0d);
	}

	@Test
	void dominanceIsComponentWiseAcrossExecutableResources() {
		ExecutionCost lowerWork = new ExecutionCost(0.0d, 10.0d, 0.0d, 20.0d, 0.0d, 0.0d);
		ExecutionCost lowerMemory = new ExecutionCost(0.0d, 20.0d, 0.0d, 10.0d, 0.0d, 0.0d);
		ExecutionCost cheaperEverywhere = new ExecutionCost(0.0d, 9.0d, 0.0d, 9.0d, 0.0d, 0.0d);

		assertFalse(lowerWork.dominates(lowerMemory));
		assertFalse(lowerMemory.dominates(lowerWork));
		assertTrue(cheaperEverywhere.dominates(lowerWork));
		assertTrue(cheaperEverywhere.dominates(lowerMemory));
	}

	@Test
	void stablePhysicalOperatorIdBreaksEqualResourceTies() {
		CostOrdering ordering = CostOrdering.forPolicy(OptimizationGoal.CostPolicy.EXACT);
		CostOrdering.RankedCost alpha = ordering.rank(work(100.0d), EstimateRisk.NONE,
				PhysicalOperatorId.of("alpha-scan"));
		CostOrdering.RankedCost beta = ordering.rank(work(100.0d), EstimateRisk.NONE,
				PhysicalOperatorId.of("beta-scan"));

		assertTrue(ordering.compare(alpha, beta) < 0);
		assertTrue(ordering.compare(beta, alpha) > 0);
	}

	@Test
	void cardinalityFactsRemainSeparateFromExecutableResources() {
		ExecutionCost resources = work(10.0d);
		CardinalityEstimate exactZero = CardinalityEstimate.exact(0.0d, "empty-values");
		CardinalityEstimate bounded = CardinalityEstimate.bounded(10.0d, 5.0d, 20.0d, "statistics");

		assertTrue(exactZero.exact());
		assertEquals(0.0d, exactZero.rows(), 0.0d);
		assertEquals(0.0d, exactZero.lowerBound(), 0.0d);
		assertEquals(0.0d, exactZero.upperBound(), 0.0d);
		assertFalse(bounded.exact());
		assertEquals(5.0d, bounded.lowerBound(), 0.0d);
		assertEquals(20.0d, bounded.upperBound(), 0.0d);
		assertEquals(10.0d, resources.totalWork(), 0.0d,
				"Cardinality evidence must not be embedded in executable resource cost");
	}

	private static ExecutionCost work(double totalWork) {
		return new ExecutionCost(0.0d, totalWork, 0.0d, 0.0d, 0.0d, 0.0d);
	}

	private static EstimateRisk risk(double qError, double confidence) {
		return new EstimateRisk(qError, 0.0d, confidence, 1.0d, "cost-ordering-test");
	}
}
